public class Main {

    static boolean isPalindrome(String text) {
        String cleaned = text.toLowerCase().replace(" ", "");
        String reversed = new StringBuilder(cleaned).reverse().toString();
        return cleaned.equals(reversed);
    }

    static boolean isNumberPalindrome(int number) {
        String text = String.valueOf(number);
        String reversed = new StringBuilder(text).reverse().toString();
        return text.equals(reversed);
    }

    public static void main(String[] args) {
        String[] words = {"kayak", "araba", "anna", "elma", "a man a plan a canal panama"};

        System.out.println("Kelime testleri:");
        for (String word : words) {
            System.out.println("'" + word + "' palindrome mu: " + isPalindrome(word));
        }

        System.out.println("\nSayi testleri:");
        int[] numbers = {12321, 12345, 1001, 5};
        for (int num : numbers) {
            System.out.println(num + " palindrome mu: " + isNumberPalindrome(num));
        }
    }
}
